import { XMarkIcon, ClockIcon, TrashIcon } from '@heroicons/react/24/outline';
import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';

export const SavedFlows = ({ isOpen, onClose }) => {
    const [history, setHistory] = useState([]);

    useEffect(() => {
        if (isOpen) {
            const saved = JSON.parse(localStorage.getItem('saved_flows') || '[]');
            setHistory(saved);
        }
    }, [isOpen]);

    const clearHistory = () => {
        localStorage.removeItem('saved_flows');
        setHistory([]);
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm"
                    />

                    <motion.div
                        initial={{ scale: 0.9, opacity: 0, y: 20 }}
                        animate={{ scale: 1, opacity: 1, y: 0 }}
                        exit={{ scale: 0.9, opacity: 0, y: 20 }}
                        className="relative w-full max-w-lg bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden"
                    >
                        <div className="p-6 border-b border-slate-800 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <ClockIcon className="w-6 h-6 text-primary" />
                                <h3 className="text-xl font-bold text-white">Execution History</h3>
                            </div>
                            <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-lg transition-colors">
                                <XMarkIcon className="w-5 h-5 text-slate-400" />
                            </button>
                        </div>

                        <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar flex flex-col gap-3">
                            {history.length > 0 ? (
                                history.map((item) => (
                                    <div key={item.id} className="bg-slate-800/40 border border-slate-700/50 rounded-xl p-4 flex items-center justify-between group hover:border-primary/30 transition-all">
                                        <div className="flex flex-col gap-1">
                                            <div className="flex items-center gap-3">
                                                <span className="text-xs font-mono text-slate-400">{new Date(item.timestamp).toLocaleTimeString()}</span>
                                                <span className={`text-[10px] px-2 py-0.5 rounded uppercase font-bold ${item.is_dag ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                                                    {item.is_dag ? 'Valid DAG' : 'Cyclic'}
                                                </span>
                                            </div>
                                            <p className="text-sm text-slate-200">
                                                <span className="text-primary font-bold">{item.nodes}</span> nodes • <span className="text-primary font-bold">{item.edges}</span> edges
                                            </p>
                                        </div>
                                        <div className="text-[10px] text-slate-500 uppercase font-bold">
                                            {new Date(item.timestamp).toLocaleDateString()}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="py-12 flex flex-col items-center justify-center text-slate-500 gap-4">
                                    <ClockIcon className="w-12 h-12 opacity-20" />
                                    <p className="text-sm italic">No recent executions found.</p>
                                </div>
                            )}
                        </div>

                        {history.length > 0 && (
                            <div className="p-6 bg-slate-900/50 border-t border-slate-800 flex justify-end">
                                <button
                                    onClick={clearHistory}
                                    className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-rose-400 hover:text-rose-300 transition-colors uppercase tracking-widest"
                                >
                                    <TrashIcon className="w-4 h-4" />
                                    Clear History
                                </button>
                            </div>
                        )}
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
};
